# Gerekli kütüphaneler
from org.apache.nifi.processor.io import StreamCallback
from org.apache.commons.io import IOUtils
from java.time import ZonedDateTime, ZoneId
from java.time.format import DateTimeFormatter
import unicodedata
import re

# Unicode normalizasyonu
def normalize_text(text):
    return unicodedata.normalize('NFKC', text)

# Non-ASCII karakterleri kaldır veya ASCII'ye yakınsayan bir eşdeğerle değiştir
def sanitize_value(value):
    if value:
        value = normalize_text(value)  # Unicode'u normalize et
        value = re.sub(r'[^\x00-\x7F]', '', value)  # Non-ASCII karakterleri kaldır
        value = value.replace("'", "''")  # SQL için tek tırnakları escape et
    return value or "NULL"

# Cluster verilerini ayrıştıran fonksiyon
def parse_cluster_data(cluster_data):
    clusters = []
    current_cluster = {}
    lines = cluster_data.strip().splitlines()
    for line in lines:
        if line.startswith('Datacenter:'):
            if current_cluster:
                clusters.append(current_cluster)
            current_cluster = {'datacenter': line.split(":")[1].strip()}
        elif ':' in line:
            key, value = line.split(":", 1)
            formatted_key = re.sub(r'[^a-zA-Z0-9\s]', '', key.strip()).replace(" ", "_").lower()
            current_cluster[formatted_key] = sanitize_value(value.strip().strip('"'))
    if current_cluster:
        clusters.append(current_cluster)
    return clusters

# SQL insert sorgusunu oluşturan fonksiyon
def generate_insert_sql(cluster_data):
    time = ZonedDateTime.now(ZoneId.of("Europe/Istanbul"))
    collection_time = time.format(DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss Z"))
    base_sql = "INSERT INTO zabbix_data ("
    column_names = []
    values_list = []
    for cluster in cluster_data:
        columns = []
        values = []
        for key, value in cluster.items():
            columns.append(key)
            values.append("'{}'".format(sanitize_value(value)))
        for col in columns:
            if col not in column_names:
                column_names.append(col)
        values_list.append("({})".format(", ".join(values)))
    sql = "{}{}) VALUES {};".format(base_sql, ", ".join(column_names), ", ".join(values_list))
    return sql

# Akış işlemini yöneten sınıf
class PyStreamCallback(StreamCallback):
    def __init__(self, table_name):
        self.table_name = table_name

    def process(self, inputStream, outputStream):
        # Read the input stream as UTF-8 directly
        try:
            input_text = IOUtils.toString(inputStream, 'utf-8')  # Assumes UTF-8 input
        except Exception as e:
            raise ValueError("Error reading input stream: {}".format(e))

        # Parse the cluster data
        parsed_clusters = parse_cluster_data(input_text)

        # Generate the SQL insert statement
        sql_statement = generate_insert_sql(parsed_clusters)

        # Write the SQL statement to the output stream
        outputStream.write(sql_statement.encode('utf-8'))



# Akış dosyasını işle
flow_file = session.get()
if flow_file is not None:
    table_name = "zabbix_data"
    session.write(flow_file, PyStreamCallback(table_name))
    session.transfer(flow_file, REL_SUCCESS)

import re from org.apache.nifi.processor.io import StreamCallback from org.apache.nifi.processor.exception import ProcessException from java.nio.charset import StandardCharsets from org.apache.commons.io import IOUtils import xml.etree.ElementTree as ET
class XMLToSQLProcessor(StreamCallback): def process(self, inputStream, outputStream): try: # Read flowfile as UTF-8 xml_content = IOUtils.toString(inputStream, "UTF-8")
# Remove the <?xml ... ?> declaration xml_content = re.sub(r"<\?xml.*?\?>", "", xml_content).strip()
# Parse XML root = ET.fromstring(xml_content)
# Extract attributes from <diskStatsColl> schema_location = root.attrib.get("{http://www.w3.org/2001/XMLSchema-instance}schemaLocation", "Not Found") timestamp = root.attrib.get("timestamp", "Not Found") node_id = root.attrib.get("id", "Not Found")
# Determine XML type based on the "contains" attribute contains_attr = root.attrib.get("contains", "") sql_statements = []
# ✅ Correct Namespace Handling (if needed) ns = {"ns": "http://ibm.com/storage/management/performance/api/2006/01/nodeStats"}
if contains_attr == "nodeStats": for node in root.findall(".//node"): sql_insert = ( "INSERT INTO IBM_Storage_node_io (node_id, timestamp, cluster, node_id_hex, cluster_id, " "ro, wo, rb, lrb, wb, lwb, \"re\", \"we\", rq, wq) VALUES " "('{node_id}', '{timestamp}', '{cluster}', '{node_id_hex}', '{cluster_id}', {ro}, {wo}, " "{rb}, {lrb}, {wb}, {lwb}, {re}, {we}, {rq}, {wq});" ).format( node_id=node_id, timestamp=timestamp, cluster=node.get("cluster", "NULL"), node_id_hex=node.get("node_id", "NULL"), cluster_id=node.get("cluster_id", "NULL"), ro=node.get("ro", "0"), wo=node.get("wo", "0"), rb=node.get("rb", "0"), lrb=node.get("lrb", "0"), wb=node.get("wb", "0"), lwb=node.get("lwb", "0"), re=node.get("re", "0"), we=node.get("we", "0"), rq=node.get("rq", "0"), wq=node.get("wq", "0") ) sql_statements.append(sql_insert)
if not sql_statements: sql_statements.append("/* No <node> elements found in XML */")
elif contains_attr == "driveStats": for mdsk in root.findall(".//mdsk"): # Debugging sql_insert = ( "INSERT INTO IBM_Storage_drive_io (node_id, timestamp, idx, ro, wo, rb, wb, re, we, rq, wq) VALUES " "('{node_id}', '{timestamp}', {idx}, {ro}, {wo}, {rb}, {wb}, {re}, {we}, {rq}, {wq});" ).format( node_id=node_id, timestamp=timestamp, idx=mdsk.get("idx", "NULL"), ro=mdsk.get("ro", "0"), wo=mdsk.get("wo", "0"), rb=mdsk.get("rb", "0"), wb=mdsk.get("wb", "0"), re=mdsk.get("re", "0"), we=mdsk.get("we", "0"), rq=mdsk.get("rq", "0"), wq=mdsk.get("wq", "0") ) sql_statements.append(sql_insert)
if not sql_statements: sql_statements.append("/* No <mdsk> elements found in XML */")
# This branch now handles both "mdiskStats" and "managedDiskStats" elif contains_attr in ("mdiskStats", "managedDiskStats"): for mdsk in root.findall(".//mdsk"): # Debugging sql_insert = ( "INSERT INTO IBM_Storage_mdsk_io (node_id, timestamp, id, ro, wo, rb, wb, re, we, rq, wq) VALUES " "('{node_id}', '{timestamp}','{id}', {ro}, {wo}, {rb}, {wb}, {re}, {we}, {rq}, {wq});" ).format( node_id=node_id, timestamp=timestamp, id=mdsk.get("id", "NULL"), ro=mdsk.get("ro", "0"), wo=mdsk.get("wo", "0"), rb=mdsk.get("rb", "0"), wb=mdsk.get("wb", "0"), re=mdsk.get("re", "0"), we=mdsk.get("we", "0"), rq=mdsk.get("rq", "0"), wq=mdsk.get("wq", "0") ) sql_statements.append(sql_insert)
if not sql_statements: sql_statements.append("/* No <mdsk> elements found in XML for managed stats */")
elif contains_attr == "virtualDiskStats": for vdsk in root.findall(".//vdsk"): sql_insert = ( "INSERT INTO IBM_Storage_vdsk_io (node_id, timestamp, id, ro, wo, rb, wb, re, we, rq, wq) VALUES " "('{node_id}', '{timestamp}', '{id}', {ro}, {wo}, {rb}, {wb}, {re}, {we}, {rq}, {wq});" ).format( node_id=node_id, timestamp=timestamp, id=vdsk.get("id", "NULL"), ro=vdsk.get("ro", "0"), wo=vdsk.get("wo", "0"), rb=vdsk.get("rb", "0"), wb=vdsk.get("wb", "0"), re=vdsk.get("re", "0"), we=vdsk.get("we", "0"), rq=vdsk.get("rq", "0"), wq=vdsk.get("wq", "0") )
sql_statements.append(sql_insert)
if not sql_statements: sql_statements.append("/* No <vdsk> elements found in XML */")
else: sql_statements.append("/* Unknown XML type */")
# Write SQL statements or comments to output outputStream.write("\n".join(sql_statements).encode("UTF-8"))
except Exception as e: raise ProcessException("Error processing XML: " + str(e))
# Process the FlowFile in NiFi flowFile = session.get() if flowFile is not None: flowFile = session.write(flowFile, XMLToSQLProcessor()) session.transfer(flowFile, REL_SUCCESS)

import re from org.apache.nifi.processor.io import StreamCallback from org.apache.nifi.processor.exception import ProcessException from java.nio.charset import StandardCharsets from org.apache.commons.io import IOUtils import xml.etree.ElementTree as ET
class XMLPortToSQLProcessor(StreamCallback): def process(self, inputStream, outputStream): try: xml_content = IOUtils.toString(inputStream, "UTF-8")
# Remove XML declaration xml_content = re.sub(r"<\?xml.*?\?>", "", xml_content).strip()
# XML namespace (update if needed) namespace = "{http://ibm.com/storage/management/performance/api/2006/01/nodeStats}" root = ET.fromstring(xml_content)
sql_statements = []
for port in root.findall(".//" + namespace + "port"): sql_insert = ( "INSERT INTO IBM_Storage_ports (port_id, type, type_id, wwpn, fc_wwpn, fcoe_wwpn, sas_wwn, iqn, " "hbt, hbr, het, her, cbt, cbr, cet, cer, lnbt, lnbr, lnet, lner, rmbt, rmbr, rmet, rmer, " "dtdt, dtdc, dtdm, dtdt2, dtdc2, lf, lsy, lsi, pspe, itw, icrc, bbcz, tmp, tmpht, txpwr, txpwrlt, " "rxpwr, rxpwrlt, hsr, hsw, har, haw) VALUES (" "'{port_id}', '{type}', {type_id}, '{wwpn}', '{fc_wwpn}', '{fcoe_wwpn}', '{sas_wwn}', '{iqn}', " "{hbt}, {hbr}, {het}, {her}, {cbt}, {cbr}, {cet}, {cer}, {lnbt}, {lnbr}, {lnet}, {lner}, {rmbt}, " "{rmbr}, {rmet}, {rmer}, {dtdt}, {dtdc}, {dtdm}, {dtdt2}, {dtdc2}, {lf}, {lsy}, {lsi}, {pspe}, " "{itw}, {icrc}, {bbcz}, {tmp}, {tmpht}, {txpwr}, {txpwrlt}, {rxpwr}, {rxpwrlt}, {hsr}, {hsw}, " "{har}, {haw});" ).format( port_id=port.get("id") or '', type=port.get("type") or '', type_id=int(port.get("type_id") or 0), wwpn=port.get("wwpn") or '', fc_wwpn=port.get("fc_wwpn") or '', fcoe_wwpn=port.get("fcoe_wwpn") or '', sas_wwn=port.get("sas_wwn") or '', iqn=port.get("iqn") or '', hbt=int(port.get("hbt") or 0), hbr=int(port.get("hbr") or 0), het=int(port.get("het") or 0), her=int(port.get("her") or 0), cbt=int(port.get("cbt") or 0), cbr=int(port.get("cbr") or 0), cet=int(port.get("cet") or 0), cer=int(port.get("cer") or 0), lnbt=int(port.get("lnbt") or 0), lnbr=int(port.get("lnbr") or 0), lnet=int(port.get("lnet") or 0), lner=int(port.get("lner") or 0), rmbt=int(port.get("rmbt") or 0), rmbr=int(port.get("rmbr") or 0), rmet=int(port.get("rmet") or 0), rmer=int(port.get("rmer") or 0), dtdt=int(port.get("dtdt") or 0), dtdc=int(port.get("dtdc") or 0), dtdm=int(port.get("dtdm") or 0), dtdt2=int(port.get("dtdt2") or 0), dtdc2=int(port.get("dtdc2") or 0), lf=int(port.get("lf") or 0), lsy=int(port.get("lsy") or 0), lsi=int(port.get("lsi") or 0), pspe=int(port.get("pspe") or 0), itw=int(port.get("itw") or 0), icrc=int(port.get("icrc") or 0), bbcz=int(port.get("bbcz") or 0), tmp=int(port.get("tmp") or 0), tmpht=int(port.get("tmpht") or 0), txpwr=int(port.get("txpwr") or 0), txpwrlt=int(port.get("txpwrlt") or 0), rxpwr=int(port.get("rxpwr") or 0), rxpwrlt=int(port.get("rxpwrlt") or 0), hsr=int(port.get("hsr") or 0), hsw=int(port.get("hsw") or 0), har=int(port.get("har") or 0), haw=int(port.get("haw") or 0) )
sql_statements.append(sql_insert)
if not sql_statements: outputStream.write("/* No <port> elements found in XML */".encode("UTF-8")) else: outputStream.write("\n".join(sql_statements).encode("UTF-8"))
except Exception as e: raise ProcessException("Error processing XML: " + str(e))
flowFile = session.get() if flowFile is not None: flowFile = session.write(flowFile, XMLPortToSQLProcessor()) session.transfer(flowFile, REL_SUCCESS)
